#ifndef KERNEL_H
#define KERNEL_H

#include <cuda_runtime.h>
#include <stdint.h>
#include <curand_kernel.h>
#include <torch/extension.h>

// Constants for Llama 3.1
constexpr int VOCAB_SIZE = 128256;
constexpr int BLOCK_SIZE = 256;

// Host wrapper function for PyTorch binding
torch::Tensor run(
    torch::Tensor probs,
    torch::Tensor top_p
);

#endif // KERNEL_H

#include "kernel.h"
#include <device_launch_parameters.h>
#include <thrust/device_ptr.h>
#include <thrust/sort.h>
#include <thrust/execution_policy.h>
#include <thrust/functional.h>
#include <thrust/iterator/counting_iterator.h>
#include <thrust/transform.h>
#include <thrust/scan.h>
#include <thrust/copy.h>
#include <thrust/sequence.h>
#include <thrust/iterator/transform_iterator.h>

// Helper struct for sorting probability-index pairs
struct __align__(8) ProbIndexPair {
    float prob;
    int index;
};

// Comparison operator for descending sort
struct CompareProbIndex {
    __device__ __forceinline__ bool operator()(const ProbIndexPair& a, const ProbIndexPair& b) const {
        return a.prob > b.prob;
    }
};

// Kernel for top-p sampling - one block per batch
__global__ void top_p_sampling_kernel(
    const float* __restrict__ probs,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    ProbIndexPair* __restrict__ d_sorted_pairs,
    float* __restrict__ d_cdf,
    curandState* __restrict__ d_states,
    int batch_size,
    int vocab_size,
    unsigned long long seed
) {
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    const float* row_probs = probs + batch_idx * vocab_size;
    float p_threshold = top_p[batch_idx];

    // Initialize random state for this batch
    curandState state;
    curand_init(seed, batch_idx, 0, &state);
    d_states[batch_idx] = state;

    int tid = threadIdx.x;
    int stride = blockDim.x;

    // Handle edge case: p_threshold <= 0.0 means argmax
    if (p_threshold <= 0.0f) {
        float max_prob = -1.0f;
        int64_t max_idx = 0;

        for (int i = tid; i < vocab_size; i += stride) {
            float p = row_probs[i];
            if (p > max_prob) {
                max_prob = p;
                max_idx = i;
            }
        }

        // Reduce to find global max
        __shared__ float shared_max_prob[BLOCK_SIZE];
        __shared__ int64_t shared_max_idx[BLOCK_SIZE];
        shared_max_prob[tid] = max_prob;
        shared_max_idx[tid] = max_idx;
        __syncthreads();

        for (int offset = BLOCK_SIZE >> 1; offset > 0; offset >>= 1) {
            if (tid < offset) {
                if (shared_max_prob[tid + offset] > shared_max_prob[tid]) {
                    shared_max_prob[tid] = shared_max_prob[tid + offset];
                    shared_max_idx[tid] = shared_max_idx[tid + offset];
                }
            }
            __syncthreads();
        }

        if (tid == 0) {
            samples[batch_idx] = shared_max_idx[0];
        }
        return;
    }

    // Handle edge case: p_threshold >= 1.0 means sample from full distribution
    if (p_threshold >= 1.0f) {
        float rand_val = curand_uniform(&d_states[batch_idx]);
        float cumsum = 0.0f;
        int64_t sampled_idx = 0;

        for (int i = 0; i < vocab_size; i++) {
            cumsum += row_probs[i];
            if (rand_val < cumsum) {
                sampled_idx = i;
                break;
            }
        }

        samples[batch_idx] = sampled_idx;
        return;
    }

    // For top-p sampling with 0 < p < 1
    // Step 1: Copy probabilities with indices to sorted buffer
    ProbIndexPair* pairs = d_sorted_pairs + batch_idx * vocab_size;
    for (int i = tid; i < vocab_size; i += stride) {
        pairs[i].prob = row_probs[i];
        pairs[i].index = i;
    }
    __syncthreads();

    // Step 2: Sort using thrust (called from host, but we prepare data here)
    // We'll use a simpler approach - just copy and let thrust sort on host

    // Step 3: Compute CDF on sorted probabilities (will be done after thrust sort)
    // For now, just copy the probabilities for CDF computation
    float* cdf_ptr = d_cdf + batch_idx * vocab_size;
    for (int i = tid; i < vocab_size; i += stride) {
        cdf_ptr[i] = pairs[i].prob;
    }
    __syncthreads();

    // Parallel prefix sum (scan) using parallel scan algorithm
    for (int offset = 1; offset < vocab_size; offset *= 2) {
        for (int i = tid; i < vocab_size; i += stride) {
            if (i >= offset) {
                cdf_ptr[i] += cdf_ptr[i - offset];
            }
        }
        __syncthreads();
    }

    // Step 4: Find cutoff index where CDF exceeds threshold
    // Need to find the first index where cdf >= p_threshold
    int cutoff_idx = vocab_size;
    for (int i = tid; i < vocab_size; i += stride) {
        if (cdf_ptr[i] >= p_threshold) {
            if (i < cutoff_idx) {
                cutoff_idx = i;
            }
        }
    }
    __syncthreads();

    // Reduce to find minimum cutoff_idx
    __shared__ int shared_cutoff[BLOCK_SIZE];
    shared_cutoff[tid] = cutoff_idx;
    __syncthreads();

    for (int offset = BLOCK_SIZE >> 1; offset > 0; offset >>= 1) {
        if (tid < offset) {
            if (shared_cutoff[tid + offset] < shared_cutoff[tid]) {
                shared_cutoff[tid] = shared_cutoff[tid + offset];
            }
        }
        __syncthreads();
    }

    int final_cutoff = shared_cutoff[0];

    // Step 5: Sample from filtered distribution (first final_cutoff elements)
    float rand_val = curand_uniform(&d_states[batch_idx]);

    // Normalize by the sum of probabilities in the top-p set
    float filtered_sum = (final_cutoff > 0) ? cdf_ptr[final_cutoff - 1] : cdf_ptr[0];
    if (filtered_sum > 0.0f) {
        float normalized_rand = rand_val * filtered_sum;

        float cumsum = 0.0f;
        int64_t sampled_idx = pairs[0].index;

        for (int i = 0; i < final_cutoff; i++) {
            cumsum += pairs[i].prob;
            if (normalized_rand < cumsum) {
                sampled_idx = pairs[i].index;
                break;
            }
        }

        if (tid == 0) {
            samples[batch_idx] = sampled_idx;
        }
    } else {
        // Fallback to argmax if sum is 0
        if (tid == 0) {
            samples[batch_idx] = pairs[0].index;
        }
    }
}

// Host wrapper function
torch::Tensor run(
    torch::Tensor probs,
    torch::Tensor top_p
) {
    // Validate inputs
    if (!probs.device().is_cuda()) {
        throw std::runtime_error("probs must be on CUDA device");
    }
    if (!top_p.device().is_cuda()) {
        throw std::runtime_error("top_p must be on CUDA device");
    }

    if (probs.dtype() != torch::kFloat32) {
        throw std::runtime_error("probs must be float32");
    }
    if (top_p.dtype() != torch::kFloat32) {
        throw std::runtime_error("top_p must be float32");
    }

    if (probs.dim() != 2) {
        throw std::runtime_error("probs must be 2D tensor");
    }
    if (top_p.dim() != 1) {
        throw std::runtime_error("top_p must be 1D tensor");
    }

    int64_t batch_size = probs.size(0);
    int64_t vocab_size = probs.size(1);

    if (vocab_size != 128256) {
        throw std::runtime_error("vocab_size must be 128256 for Llama 3.1");
    }

    if (top_p.size(0) != batch_size) {
        throw std::runtime_error("top_p size must match batch_size");
    }

    if (!probs.is_contiguous()) {
        throw std::runtime_error("probs must be contiguous");
    }
    if (!top_p.is_contiguous()) {
        throw std::runtime_error("top_p must be contiguous");
    }

    // Create output tensor
    auto samples = torch::empty(
        {batch_size},
        torch::dtype(torch::kInt64).device(probs.device())
    );

    // Allocate device memory for temporary buffers
    ProbIndexPair* d_sorted_pairs = nullptr;
    float* d_cdf = nullptr;
    curandState* d_states = nullptr;

    cudaError_t err;

    // Allocate per-batch buffers (batch_size * vocab_size)
    err = cudaMalloc((void**)&d_sorted_pairs, batch_size * vocab_size * sizeof(ProbIndexPair));
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("cudaMalloc failed for d_sorted_pairs: ") + cudaGetErrorString(err));
    }

    err = cudaMalloc((void**)&d_cdf, batch_size * vocab_size * sizeof(float));
    if (err != cudaSuccess) {
        cudaFree(d_sorted_pairs);
        throw std::runtime_error(std::string("cudaMalloc failed for d_cdf: ") + cudaGetErrorString(err));
    }

    err = cudaMalloc((void**)&d_states, batch_size * sizeof(curandState));
    if (err != cudaSuccess) {
        cudaFree(d_sorted_pairs);
        cudaFree(d_cdf);
        throw std::runtime_error(std::string("cudaMalloc failed for d_states: ") + cudaGetErrorString(err));
    }

    // Get raw pointers
    const float* probs_ptr = probs.data_ptr<float>();
    const float* top_p_ptr = top_p.data_ptr<float>();
    int64_t* samples_ptr = samples.data_ptr<int64_t>();

    // Launch configuration optimized for A800
    int threads_per_block = 256;
    int blocks = batch_size;

    // Launch kernel
    top_p_sampling_kernel<<<blocks, threads_per_block>>>(
        probs_ptr,
        top_p_ptr,
        samples_ptr,
        d_sorted_pairs,
        d_cdf,
        d_states,
        static_cast<int>(batch_size),
        static_cast<int>(vocab_size),
        42  // seed
    );

    // Check for errors
    err = cudaGetLastError();
    if (err != cudaSuccess) {
        cudaFree(d_sorted_pairs);
        cudaFree(d_cdf);
        cudaFree(d_states);
        throw std::runtime_error(std::string("CUDA kernel error: ") + cudaGetErrorString(err));
    }

    // Synchronize
    cudaDeviceSynchronize();

    // Free device memory
    cudaFree(d_sorted_pairs);
    cudaFree(d_cdf);
    cudaFree(d_states);

    return samples;
}

#include <torch/extension.h>
#include <torch/cuda.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"
#include <stdexcept>
#include <iostream>

// PyTorch binding
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, 
          "Top-p sampling from probability distributions for Llama 3.1",
          py::arg("probs"),
          py::arg("top_p"));
}
